import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it("should return empty array for empty input", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("should kill a single live cell with no neighbors (underpopulation)", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });
  it.todo("should kill two adjacent live cells each with one neighbor (underpopulation)");
  it.todo("should keep a block of 2x2 cells unchanged (still life, survival)");
  it.todo("should transform a vertical blinker into a horizontal blinker (survival and reproduction)");
  it.todo("should kill a live cell with more than 3 neighbors (overpopulation)");
  it.todo("should bring a dead cell to life when it has exactly 3 neighbors (reproduction)");
  it.todo("should handle negative coordinates");
});

